export const progressEventReducer = (listener, isDownloadStream, freq = 3) => {
  let bytesNotified = 0;
  const _speedometer = speedometer(50, 250);

  return throttle((e) => {
    if (!e || typeof e.loaded !== 'number') {
      return;
    }
    const rawLoaded = e.loaded;
    const total = e.lengthComputable ? e.total : undefined;
    const loaded = total != null ? Math.min(rawLoaded, total) : rawLoaded;
    const progressBytes = Math.max(0, loaded - bytesNotified);
    const rate = _speedometer(progressBytes);

    bytesNotified = Math.max(bytesNotified, loaded);

    const data = {
      loaded,
      total,
      progress: total ? loaded / total : undefined,
      bytes: progressBytes,
      rate: rate ? rate : undefined,
      estimated: rate && total ? (total - loaded) / rate : undefined,
      event: e,
      lengthComputable: total != null,
      [isDownloadStream ? 'download' : 'upload']: true,
    };

    listener(data);
  }, freq);
};

function speedometer(samplesCount, min) {
  samplesCount = samplesCount || 10;
  const bytes = new Array(samplesCount);
  const timestamps = new Array(samplesCount);
  let head = 0;
  let tail = 0;
  let firstSampleTS;

  min = min !== undefined ? min : 1000;

  return function push(chunkLength) {
    const now = Date.now();

    const startedAt = timestamps[tail];

    if (!firstSampleTS) {
      firstSampleTS = now;
    }

    bytes[head] = chunkLength;
    timestamps[head] = now;

    let i = tail;
    let bytesCount = 0;

    while (i !== head) {
      bytesCount += bytes[i++];
      i = i % samplesCount;
    }

    head = (head + 1) % samplesCount;

    if (head === tail) {
      tail = (tail + 1) % samplesCount;
    }

    if (now - firstSampleTS < min) {
      return;
    }

    const passed = startedAt && now - startedAt;

    return passed ? Math.round((bytesCount * 1000) / passed) : undefined;
  };
}

function getRuleOptionsSchema(rule) {
	if (!rule.meta) {
		return { ...noOptionsSchema }; // default if `meta.schema` is not specified
	}

	const schema = rule.meta.schema;

	if (typeof schema === "undefined") {
		return { ...noOptionsSchema }; // default if `meta.schema` is not specified
	}

	// `schema:false` is an allowed explicit opt-out of options validation for the rule
	if (schema === false) {
		return null;
	}

	if (typeof schema !== "object" || schema === null) {
		throw new TypeError("Rule's `meta.schema` must be an array or object");
	}

	// ESLint-specific array form needs to be converted into a valid JSON Schema definition
	if (Array.isArray(schema)) {
		if (schema.length) {
			return {
				type: "array",
				items: schema,
				minItems: 0,
				maxItems: schema.length,
			};
		}

		// `schema:[]` is an explicit way to specify that the rule does not accept any options
		return { ...noOptionsSchema };
	}

	// `schema:<object>` is assumed to be a valid JSON Schema definition
	return schema;
}

function doesRuleSupportLanguage(
	ruleLangs,
	configLanguageName,
	validPluginNames,
) {
	// If no languages specified, works with all languages (backward compatible)
	if (!ruleLangs) {
		return true;
	}

	const { objectName: configLangPart } =
		splitPluginIdentifier(configLanguageName);

	for (const langEntry of ruleLangs) {
		// Skip non-string entries
		if (typeof langEntry !== "string") {
			continue;
		}

		// "*" matches any language
		if (langEntry === "*") {
			return true;
		}

		// Direct match
		if (langEntry === configLanguageName) {
			return true;
		}

		const { pluginName: rulePluginPart, objectName: ruleLangPart } =
			splitPluginIdentifier(langEntry);

		// "plugin/*" wildcard - matches any language from that plugin (by name or namespace)
		if (ruleLangPart === "*") {
			if (validPluginNames.includes(rulePluginPart)) {
				return true;
			}
		} else {
			// Match by plugin name or namespace, with exact language part
			if (
				validPluginNames.includes(rulePluginPart) &&
				ruleLangPart === configLangPart
			) {
				return true;
			}
		}
	}

	return false;
}

function checkList(nodes) {
	const accessors = [];
	let found = false;

	for (let i = 0; i < nodes.length; i++) {
		const node = nodes[i];

		if (isAccessorKind(node)) {
			// Creates a new `AccessorData` object for the given getter or setter node.
			const name = astUtils.getStaticPropertyName(node);
			const key =
				name !== null ? name : sourceCode.getTokens(node.key);

			// Merges the given `AccessorData` object into the given accessors list.
			for (let j = 0; j < accessors.length; j++) {
				const accessor = accessors[j];

				if (areEqualKeys(accessor.key, key)) {
					accessor.getters.push(
						...(node.kind === "get" ? [node] : []),
					);
					accessor.setters.push(
						...(node.kind === "set" ? [node] : []),
					);
					found = true;
					break;
				}
			}
			if (!found) {
				accessors.push({
					key,
					getters: node.kind === "get" ? [node] : [],
					setters: node.kind === "set" ? [node] : [],
				});
			}
			found = false;
		}
	}

	for (const { getters, setters } of accessors) {
		if (checkSetWithoutGet && setters.length && !getters.length) {
			reportList(setters, "missingGetter");
		}
		if (checkGetWithoutSet && getters.length && !setters.length) {
			reportList(getters, "missingSetter");
		}
	}
}

function checkNode(node) {
	const importSource = node.source.value.trim();
	const importNames = new Map();

	if (node.type === "ExportAllDeclaration") {
		const starToken = sourceCode.getFirstToken(node, 1);

		importNames.set("*", [{ loc: starToken.loc }]);
	} else if (node.specifiers) {
		for (const specifier of node.specifiers) {
			let name;
			const specifierData = { loc: specifier.loc, specifier };

			if (specifier.type === "ImportDefaultSpecifier") {
				name = "default";
			} else if (specifier.type === "ImportNamespaceSpecifier") {
				name = "*";
			} else if (specifier.imported) {
				name = astUtils.getModuleExportName(specifier.imported);
			} else if (specifier.local) {
				name = astUtils.getModuleExportName(specifier.local);
			}

			if (typeof name === "string") {
				if (importNames.has(name)) {
					importNames.get(name).push(specifierData);
				} else {
					importNames.set(name, [specifierData]);
				}
			}
		}
	}

	checkRestrictedPathAndReport(importSource, importNames, node);
	restrictedPatternGroups.forEach(group => {
		if (isRestrictedPattern(importSource, group)) {
			reportPathForPatterns(
				node,
				group,
				importNames,
				importSource,
			);
		}
	});
}

function reportUnnecessaryAwait(node) {
	context.report({
		node: context.sourceCode.getFirstToken(node),
		loc: node.loc,
		messageId: "redundantUseOfAwait",
		suggest: [
			{
				messageId: "removeAwait",
				fix(fixer) {
					const sourceCode = context.sourceCode;
					const [awaitToken, tokenAfterAwait] =
						sourceCode.getFirstTokens(node, 2);

					const areAwaitAndAwaitedExpressionOnTheSameLine =
						awaitToken.loc.start.line ===
						tokenAfterAwait.loc.start.line;

					if (!areAwaitAndAwaitedExpressionOnTheSameLine) {
						return null;
					}

					const [startOfAwait, endOfAwait] = awaitToken.range;

					const characterAfterAwait =
						sourceCode.text[endOfAwait];
					const trimLength =
						characterAfterAwait === " " ? 1 : 0;

					const range = [
						startOfAwait,
						endOfAwait + trimLength,
					];

					return fixer.removeRange(range);
				},
			},
		],
	});
}

function checkArguments(node) {
	const args = node.arguments;

	switch (args.length) {
		case 0:
			context.report({
				node,
				messageId: "missingParameters",
			});
			break;

		case 1:
			context.report({
				node,
				messageId: "missingRadix",
				suggest: [
					{
						messageId: "addRadixParameter10",
						fix(fixer) {
							const tokens = sourceCode.getTokens(node);
							const lastToken = tokens.at(-1); // Parenthesis.
							const secondToLastToken = tokens.at(-2); // May or may not be a comma.
							const hasTrailingComma =
								secondToLastToken.type ===
									"Punctuator" &&
								secondToLastToken.value === ",";

							return fixer.insertTextBefore(
								lastToken,
								hasTrailingComma ? " 10," : ", 10",
							);
						},
					},
				],
			});
			break;

		default:
			if (!isValidRadix(args[1])) {
				context.report({
					node,
					messageId: "invalidRadix",
				});
			}
			break;
	}
}

function checkPrecedingSpace(node) {
	const precedingToken = sourceCode.getTokenBefore(node);

	if (
		precedingToken &&
		!isConflicted(precedingToken, node) &&
		astUtils.isTokenOnSameLine(precedingToken, node)
	) {
		const hasSpace = sourceCode.isSpaceBetween(
			precedingToken,
			node,
		);
		let requireSpace;
		let requireNoSpace;

		if (isFunctionBody(node)) {
			requireSpace = alwaysFunctions;
			requireNoSpace = neverFunctions;
		} else if (node.type === "ClassBody") {
			requireSpace = alwaysClasses;
			requireNoSpace = neverClasses;
		} else {
			requireSpace = alwaysKeywords;
			requireNoSpace = neverKeywords;
		}

		if (requireSpace && !hasSpace) {
			context.report({
				node,
				messageId: "missingSpace",
				fix(fixer) {
					return fixer.insertTextBefore(node, " ");
				},
			});
		} else if (requireNoSpace && hasSpace) {
			context.report({
				node,
				messageId: "unexpectedSpace",
				fix(fixer) {
					return fixer.removeRange([
						precedingToken.range[1],
						node.range[0],
					]);
				},
			});
		}
	}
}

function checkFunction(node) {
	const functionConfig = getConfigForFunction(node);

	if (functionConfig === "ignore") {
		return;
	}

	const rightToken = sourceCode.getFirstToken(
		node,
		astUtils.isOpeningParenToken,
	);
	const leftToken = sourceCode.getTokenBefore(rightToken);
	const hasSpacing = sourceCode.isSpaceBetween(leftToken, rightToken);

	if (hasSpacing && functionConfig === "never") {
		context.report({
			node,
			loc: {
				start: leftToken.loc.end,
				end: rightToken.loc.start,
			},
			messageId: "unexpectedSpace",
			fix(fixer) {
				const comments =
					sourceCode.getCommentsBefore(rightToken);

				// Don't fix anything if there's a single line comment between the left and the right token
				if (comments.some(comment => comment.type === "Line")) {
					return null;
				}
				return fixer.replaceTextRange(
					[leftToken.range[1], rightToken.range[0]],
					comments.reduce(
						(text, comment) =>
							text + sourceCode.getText(comment),
						"",
					),
				);
			},
		});
	} else if (!hasSpacing && functionConfig === "always") {
		context.report({
			node,
			loc: rightToken.loc,
			messageId: "missingSpace",
			fix: fixer => fixer.insertTextAfter(leftToken, " "),
		});
	}
}

function checkForSpaces(node) {
	const tokens =
		node.type === "UpdateExpression" && !node.prefix
			? sourceCode.getLastTokens(node, 2)
			: sourceCode.getFirstTokens(node, 2);
	const firstToken = tokens[0];
	const secondToken = tokens[1];

	if (
		(node.type === "NewExpression" || node.prefix) &&
		firstToken.type === "Keyword"
	) {
		checkUnaryWordOperatorForSpaces(
			node,
			firstToken,
			secondToken,
			firstToken.value,
		);
		return;
	}

	const operator = node.prefix ? tokens[0].value : tokens[1].value;

	if (overrideExistsForOperator(operator)) {
		if (overrideEnforcesSpaces(operator)) {
			verifyNonWordsHaveSpaces(node, firstToken, secondToken);
		} else {
			verifyNonWordsDontHaveSpaces(node, firstToken, secondToken);
		}
	} else if (options.nonwords) {
		verifyNonWordsHaveSpaces(node, firstToken, secondToken);
	} else {
		verifyNonWordsDontHaveSpaces(node, firstToken, secondToken);
	}
}

function getJSDocComment(node, sourceCode) {
	let parent = node.parent;

	switch (node.type) {
		case "ClassDeclaration":
		case "FunctionDeclaration":
			return findJSDocComment(
				isExportDeclaration(parent) ? parent : node,
				sourceCode,
			);

		case "ClassExpression":
			return findJSDocComment(parent.parent, sourceCode);

		case "ArrowFunctionExpression":
		case "FunctionExpression":
			if (
				parent.type !== "CallExpression" &&
				parent.type !== "NewExpression"
			) {
				while (
					!sourceCode.getCommentsBefore(parent).length &&
					!/Function/u.test(parent.type) &&
					parent.type !== "MethodDefinition" &&
					parent.type !== "Property"
				) {
					parent = parent.parent;

					if (!parent) {
						break;
					}
				}

				if (
					parent &&
					parent.type !== "FunctionDeclaration" &&
					parent.type !== "Program"
				) {
					return findJSDocComment(parent, sourceCode);
				}
			}

			return findJSDocComment(node, sourceCode);

		// falls through
		default:
			return null;
	}
}

function withPlugins(
  fn,
  optionsArgumentIndex = 1, // Usually `options` is the 2nd argument
) {
  return async (...args) => {
    const options = args[optionsArgumentIndex] ?? {};
    const { plugins = [] } = options;

    args[optionsArgumentIndex] = {
      ...options,
      plugins: (
        await Promise.all([
          loadBuiltinPlugins(),
          // TODO: standalone version allow `plugins` to be `prettierPlugins` which is an object, should allow that too
          loadPlugins(plugins),
        ])
      ).flat(),
    };

    return fn(...args);
  };
}

const formatWithCursor = withPlugins(core.formatWithCursor);

async function format(text, options) {
  const { formatted } = await formatWithCursor(text, {
    ...options,
    cursorOffset: -1,
  });
  return formatted;
}

async function check(text, options) {
  return (await format(text, options)) === text;
}

// eslint-disable-next-line require-await

export function getOptions(opts) {
  let options = {}

  for (let opt in defaultOptions)
    options[opt] = opts && hasOwn(opts, opt) ? opts[opt] : defaultOptions[opt]

  if (options.ecmaVersion === "latest") {
    options.ecmaVersion = 1e8
  } else if (options.ecmaVersion == null) {
    if (!warnedAboutEcmaVersion && typeof console === "object" && console.warn) {
      warnedAboutEcmaVersion = true
      console.warn("Since Acorn 8.0.0, options.ecmaVersion is required.\nDefaulting to 2020, but this will stop working in the future.")
    }
    options.ecmaVersion = 11
  } else if (options.ecmaVersion >= 2015) {
    options.ecmaVersion -= 2009
  }

  if (options.allowReserved == null)
    options.allowReserved = options.ecmaVersion < 5

  if (!opts || opts.allowHashBang == null)
    options.allowHashBang = options.ecmaVersion >= 14

  if (isArray(options.onToken)) {
    let tokens = options.onToken
    options.onToken = (token) => tokens.push(token)
  }
  if (isArray(options.onComment))
    options.onComment = pushComment(options, options.onComment)

  if (options.sourceType === "commonjs" && options.allowAwaitOutsideFunction)
    throw new Error("Cannot use allowAwaitOutsideFunction with sourceType: commonjs")

  return options
}

function initOptions(toOptions, fromOptions) {
	if (typeof fromOptions.align === "object") {
		// Initialize the alignment configuration
		toOptions.align = initOptionProperty({}, fromOptions.align);
		toOptions.align.on = fromOptions.align.on || "colon";
		toOptions.align.mode = fromOptions.align.mode || "strict";

		toOptions.multiLine = initOptionProperty(
			{},
			fromOptions.multiLine || fromOptions,
		);
		toOptions.singleLine = initOptionProperty(
			{},
			fromOptions.singleLine || fromOptions,
		);
	} else {
		// string or undefined
		toOptions.multiLine = initOptionProperty(
			{},
			fromOptions.multiLine || fromOptions,
		);
		toOptions.singleLine = initOptionProperty(
			{},
			fromOptions.singleLine || fromOptions,
		);

		// If alignment options are defined in multiLine, pull them out into the general align configuration
		if (toOptions.multiLine.align) {
			toOptions.align = {
				on: toOptions.multiLine.align.on,
				mode:
					toOptions.multiLine.align.mode || toOptions.multiLine.mode,
				beforeColon: toOptions.multiLine.align.beforeColon,
				afterColon: toOptions.multiLine.align.afterColon,
			};
		}
	}

	return toOptions;
}

function checkBinaryLogical(node) {
	const prec = precedence(node);
	const leftPrecedence = precedence(node.left);
	const rightPrecedence = precedence(node.right);
	const isExponentiation = node.operator === "**";
	const shouldSkipLeft =
		NESTED_BINARY &&
		(node.left.type === "BinaryExpression" ||
			node.left.type === "LogicalExpression");
	const shouldSkipRight =
		NESTED_BINARY &&
		(node.right.type === "BinaryExpression" ||
			node.right.type === "LogicalExpression");

	if (!shouldSkipLeft && hasExcessParens(node.left)) {
		if (
			(!(
				["AwaitExpression", "UnaryExpression"].includes(
					node.left.type,
				) && isExponentiation
			) &&
				!astUtils.isMixedLogicalAndCoalesceExpressions(
					node.left,
					node,
				) &&
				(leftPrecedence > prec ||
					(leftPrecedence === prec && !isExponentiation))) ||
			isParenthesisedTwice(node.left)
		) {
			report(node.left);
		}
	}

	if (!shouldSkipRight && hasExcessParens(node.right)) {
		if (
			(!astUtils.isMixedLogicalAndCoalesceExpressions(
				node.right,
				node,
			) &&
				(rightPrecedence > prec ||
					(rightPrecedence === prec && isExponentiation))) ||
			isParenthesisedTwice(node.right)
		) {
			report(node.right);
		}
	}
}

function hasOnlyOneStatement(statementType, declarations) {
	const declarationCounts = countDeclarations(declarations);
	const currentOptions = options[statementType] || {};
	const currentScope = getCurrentScope(statementType);
	const hasRequires = declarations.some(isRequire);

	if (
		currentOptions.uninitialized === MODE_ALWAYS &&
		currentOptions.initialized === MODE_ALWAYS
	) {
		if (currentScope.uninitialized || currentScope.initialized) {
			if (!hasRequires) {
				return false;
			}
		}
	}

	if (declarationCounts.uninitialized > 0) {
		if (
			currentOptions.uninitialized === MODE_ALWAYS &&
			currentScope.uninitialized
		) {
			return false;
		}
	}
	if (declarationCounts.initialized > 0) {
		if (
			currentOptions.initialized === MODE_ALWAYS &&
			currentScope.initialized
		) {
			if (!hasRequires) {
				return false;
			}
		}
	}
	if (currentScope.required && hasRequires) {
		return false;
	}
	recordTypes(statementType, declarations, currentScope);
	return true;
}

function joinDeclarations(declarations) {
	const declaration = declarations[0];
	const body = Array.isArray(declaration.parent.parent.body)
		? declaration.parent.parent.body
		: [];
	const currentIndex = body.findIndex(
		node => node.range[0] === declaration.parent.range[0],
	);
	const previousNode = body[currentIndex - 1];

	return function* joinDeclarationsFixer(fixer) {
		const type = sourceCode.getFirstToken(declaration.parent);
		const beforeType = sourceCode.getTokenBefore(type);

		if (
			previousNode &&
			previousNode.kind === declaration.parent.kind
		) {
			if (beforeType.value === ";") {
				yield fixer.replaceText(beforeType, ",");
			} else {
				yield fixer.insertTextAfter(beforeType, ",");
			}

			if (declaration.parent.kind === "await using") {
				const usingToken = sourceCode.getTokenAfter(type);
				yield fixer.remove(usingToken);
			}

			yield fixer.replaceText(type, "");
		}
	};
}

function checkSpacingBefore(token) {
	if (!token.value.startsWith("}")) {
		return; // starts with a backtick, this is the first template element in the template literal
	}

	const prevToken = sourceCode.getTokenBefore(token, {
			includeComments: true,
		}),
		hasSpace = sourceCode.isSpaceBetween(prevToken, token);

	if (!astUtils.isTokenOnSameLine(prevToken, token)) {
		return;
	}

	if (always && !hasSpace) {
		context.report({
			loc: {
				start: token.loc.start,
				end: {
					line: token.loc.start.line,
					column: token.loc.start.column + 1,
				},
			},
			messageId: "expectedBefore",
			fix: fixer => fixer.insertTextBefore(token, " "),
		});
	}

	if (!always && hasSpace) {
		context.report({
			loc: {
				start: prevToken.loc.end,
				end: token.loc.start,
			},
			messageId: "unexpectedBefore",
			fix: fixer =>
				fixer.removeRange([prevToken.range[1], token.range[0]]),
		});
	}
}

function getTextPositionsMap(sourceText, consideredRuleIds) {
	const textPositionsMap = new Map();
	const ast = ts.createSourceFile("", sourceText);

	for (const statement of ast.statements) {
		if (
			statement.kind === ts.SyntaxKind.InterfaceDeclaration &&
			extendsRulesRecord(statement)
		) {
			const { members } = statement;

			for (const member of members) {
				if (member.kind === ts.SyntaxKind.PropertySignature) {
					const ruleId = member.name.text;

					if (consideredRuleIds.has(ruleId)) {
						let textPositions;

						// Only the last TSDoc comment is regarded.
						const tsDoc = member.jsDoc?.at(-1);

						if (tsDoc) {
							textPositions = {
								tsDocStart: tsDoc.pos,
								tsDocEnd: tsDoc.end,
							};
						} else {
							const regExp = /\S/gu;

							regExp.lastIndex = member.pos;
							const { index } = regExp.exec(sourceText);

							textPositions = {
								tsDocStart: index,
								tsDocEnd: index,
							};
						}
						textPositions.typeEnd = member.end;
						textPositionsMap.set(ruleId, textPositions);
					}
				}
			}
		}
	}
	return textPositionsMap;
}
